input.command:
# Use localhost exception to connect without auth and create users
kubectl exec -n mongodb mongodb-replica-0 -- mongosh --quiet --eval '
db = db.getSiblingDB("admin");
// Check if users exist
var users = db.system.users.find().toArray();
print("Existing users:", users.length);
' 2>&1 | grep -v "^Default"

# Try connecting explicitly to localhost - keyFile may interfere with localhost exception
kubectl exec -n mongodb mongodb-replica-0 -- mongosh --host 127.0.0.1 --port 27017 --quiet admin --eval '
try {
  db.createUser({user:"admin",pwd:"admin123password",roles:[{role:"root",db:"admin"}]});
  print("created");
} catch(e) {
  print("err:", e.message);
}
' 2>&1 | grep -v "^Default"

