# Create a dedicated monitoring user in MongoDB
kubectl exec -n mongodb mongodb-replica-0 -- mongosh --quiet admin \
  -u admin-user -p admin123password --authenticationDatabase admin \
  --eval '
db.createUser({
  user: "prometheus",
  pwd: "prom_monitor_pass",
  roles: [
    { role: "clusterMonitor", db: "admin" },
    { role: "read", db: "local" }
  ]
});
print("user created");
' 2>&1 | grep -v Default

# Create monitoring user on the primary (mongodb-replica-2)
kubectl exec -n mongodb mongodb-replica-2 -- mongosh --quiet admin \
  -u admin-user -p admin123password --authenticationDatabase admin \
  --eval '
db.createUser({
  user: "prometheus",
  pwd: "prom_monitor_pass",
  roles: [
    { role: "clusterMonitor", db: "admin" },
    { role: "read", db: "local" }
  ]
});
print("user created");
' 2>&1 | grep -v Default
